sys_module.content:
var InsuranceNotificationUtils = Class.create();
InsuranceNotificationUtils.prototype = {
    initialize: function() {},

    sendPolicyExpiryNotification: function(policyRecord) {
        // Send notification for policy expiry
        var clientName = policyRecord.getValue('client_name');
        var policyNumber = policyRecord.getValue('policy_number');
        var expiryDate = policyRecord.getValue('policy_end_date');
        var contactEmail = policyRecord.getValue('contact_email');

        if (!gs.nil(contactEmail)) {
            gs.eventQueue('insurance.policy.expiry.reminder', policyRecord, 
                         clientName, policyNumber, expiryDate, contactEmail);

            gs.info('Policy expiry notification queued for: ' + clientName + 
                   ' (Policy: ' + policyNumber + ')');
        }
    },

    sendRenewalNotification: function(renewalRecord) {
        // Send notification for renewal updates
        var clientRef = renewalRecord.getValue('client_reference');
        var renewalStatus = renewalRecord.getValue('renewal_status');

        if (!gs.nil(clientRef)) {
            var clientGR = new GlideRecord('x_1945663_insuranc_u_insurance_clients_data');
            if (clientGR.get(clientRef)) {
                var clientName = clientGR.getValue('client_name');
                var contactEmail = clientGR.getValue('contact_email');

                if (!gs.nil(contactEmail)) {
                    gs.eventQueue('insurance.renewal.status.update', renewalRecord,
                                 clientName, renewalStatus, contactEmail);

                    gs.info('Renewal notification sent to: ' + clientName + 
                           ' for status: ' + renewalStatus);
                }
            }
        }
    },

    sendClaimsNotification: function(claimsRecord, statusChange) {
        // Send notification for claims updates
        var clientRef = claimsRecord.getValue('client_reference');
        var claimNumber = claimsRecord.getValue('claim_number');
        var claimStatus = claimsRecord.getValue('claim_status');

        if (!gs.nil(clientRef)) {
            var clientGR = new GlideRecord('x_1945663_insuranc_u_insurance_clients_data');
            if (clientGR.get(clientRef)) {
                var clientName = clientGR.getValue('client_name');
                var contactEmail = clientGR.getValue('contact_email');

                if (!gs.nil(contactEmail)) {
                    gs.eventQueue('insurance.claim.status.update', claimsRecord,
                                 clientName, claimNumber, claimStatus, contactEmail);

                    gs.info('Claim notification sent to: ' + clientName + 
                           ' for claim: ' + claimNumber + ' - Status: ' + claimStatus);
                }
            }
        }
    },

    type: 'InsuranceNotificationUtils'
};
